VALUES (CTR-413, NULL, '裸花紫珠颗粒中药保护临床研究试验', 'SERVICE', '421', 'SPONSOR', 'SPN-232', 7000000.0, 1919600.0, 1919600.0, 5080400.0, '2022-10-10', '2022-10-10', NULL, 'EXECUTING', NULL, NULL, 5, 0, '由于本合同签订之时，需要根据按照最终定稿的临床试验方案中，第一阶段的期中趋势分析来调整第二阶段的样本量，而第二阶段试验样本量的确定不仅需要满足法规要求，而且还有具有统计学意义，故暂按第二阶段468例来计算报价。因此，按第一阶段趋势分析确定的第二阶段试验病例数，如与目前报价的病例数量（第二阶段468例）不符，则按方案实际病例数相应地增加或减少相关试验费用，甲乙双方根据情况另行签署补充协议。', '2022-10-28 11:06:52', '2022-10-28 11:06:52', 'HR-764', 'SYSTEM');
